canvas.init:
function init(canvas, params) {
  var ctx = canvas.getContext('2d');
  var W = canvas.width, H = canvas.height;
  var N = params.particles || 60;
  var LD = params.linkDistance || 50;
  var SP = params.speed || 1.0;
  var color = getComputedStyle(canvas).getPropertyValue('--ct-text-strong').trim() || '#ffffff';
  var ps = [];
  for (var i = 0; i < N; i++) {
    ps.push({ x: Math.random() * W, y: Math.random() * H, vx: (Math.random() - 0.5) * SP, vy: (Math.random() - 0.5) * SP });
  }
  function draw() {
    ctx.clearRect(0, 0, W, H);
    ps.forEach(function(p) {
      p.x += p.vx; p.y += p.vy;
      if (p.x < 0 || p.x > W) p.vx *= -1;
      if (p.y < 0 || p.y > H) p.vy *= -1;
    });
    ctx.lineWidth = 0.5;
    for (var i = 0; i < ps.length; i++) {
      for (var j = i + 1; j < ps.length; j++) {
        var dx = ps[i].x - ps[j].x, dy = ps[i].y - ps[j].y;
        var d = Math.sqrt(dx * dx + dy * dy);
        if (d < LD) {
          ctx.beginPath();
          ctx.moveTo(ps[i].x, ps[i].y);
          ctx.lineTo(ps[j].x, ps[j].y);
          ctx.globalAlpha = 1 - d / LD;
          ctx.strokeStyle = color;
          ctx.stroke();
        }
      }
    }
    ctx.globalAlpha = 0.8;
    ps.forEach(function(p) {
      ctx.beginPath();
      ctx.arc(p.x, p.y, 1.5, 0, Math.PI * 2);
      ctx.fillStyle = color;
      ctx.fill();
    });
    ctx.globalAlpha = 1;
    requestAnimationFrame(draw);
  }
  draw();
}
